export function searchMedicines(q){
  if(!q||q.length<2)return[];
  const ql=q.toLowerCase();const r=[];
  for(let i=0;i<MEDICINES.length;i++){
    if(MEDICINES[i].toLowerCase().includes(ql)){
      r.push(MEDICINES[i]);if(r.length>=8)break;
    }
  }
  return r;
}
